  // Rule of thumb: connections = (CPU cores * 2) + disk spindles
  // For 200 req/s with 50ms queries, you need ~10-15 concurrent
  max: 20,                    // Current: OK if leak is fixed
  idleTimeoutMillis: 30000,   // Close idle connections after 30s
  connectionTimeoutMillis: 2000, // Fail fast if pool exhausted
});
```

