    await client.query(
      'UPDATE accounts SET balance = balance + $1 WHERE id = $2',
      [req.body.amount, req.body.toId]
    );

    await client.query('COMMIT');
    res.json({ success: true });

  } catch (error) {
    await client.query('ROLLBACK');
    console.error(error);
    res.status(500).json({ error: 'Transfer failed' });
  } finally {
    client.release(); // Still required here
  }
});
```

## Pool Configuration

```javascript
import { Pool } from 'pg';

const pool = new Pool({
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,

  // Size: (num_cores * 2) + effective_spindle_count
  // For 4-core machine with SSD: start at 10, tune from there
  max: 20,

  // Don't wait forever for a connection
  connectionTimeoutMillis: 5000,  // Fail fast: 5s max wait

  // Kill idle connections (saves DB resources)
  idleTimeoutMillis: 30000,       // 30s idle before release

  // Detect broken connections before using them
  allowExitOnIdle: false,
});

// Monitor pool health - critical for production
pool.on('connect', () => {
  console.debug(`Pool size: ${pool.totalCount} | Idle: ${pool.idleCount} | Waiting: ${pool.waitingCount}`);
});

pool.on('error', (error) => {
  // Unexpected errors on idle clients
  console.error('Pool error:', error.message);
});

// Expose metrics endpoint for alerting
app.get('/health/db', async (req, res) => {
  res.json({
    total: pool.totalCount,
    idle: pool.idleCount,
    waiting: pool.waitingCount,
    // Alert if waiting > 0 for more than a few seconds
  });
});
```

